package com.example.shareapp;

import android.app.Activity;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.widget.ImageView;
import android.widget.TextView;
import android.widget.Toast;
import androidx.annotation.Nullable;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;

public class ShareReceiverActivity extends Activity {

    private static final String TAG = "ShareReceiverActivity";
    private static final int MAX_TEXT_LENGTH = 10000;
    private static final Set<String> ALLOWED_IMAGE_TYPES = new HashSet<>(Arrays.asList(
            "image/jpeg", "image/jpg", "image/png", "image/gif", "image/webp"
    ));
    private static final Set<String> ALLOWED_PACKAGES = new HashSet<>(Arrays.asList(
            "com.android.chrome",
            "com.android.browser",
            "com.google.android.apps.photos",
            "com.android.gallery3d",
            "com.sec.android.gallery3d",
            "com.miui.gallery",
            "com.oneplus.gallery",
            "org.mozilla.firefox",
            "com.opera.browser",
            "com.microsoft.emmx",
            "com.brave.browser"
    ));

    private TextView textView;
    private ImageView imageView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_share_receiver);

        textView = findViewById(R.id.sharedTextView);
        imageView = findViewById(R.id.sharedImageView);

        Intent intent = getIntent();
        if (intent == null) {
            showError("No intent received");
            finish();
            return;
        }

        if (!validateCaller(intent)) {
            showError("Unauthorized caller");
            finish();
            return;
        }

        if (!validateIntent(intent)) {
            showError("Invalid intent data");
            finish();
            return;
        }

        handleIntent(intent);
    }

    private boolean validateCaller(Intent intent) {
        String callingPackage = getCallingPackage();
        if (callingPackage == null) {
            callingPackage = intent.getPackage();
        }

        if (callingPackage == null) {
            Uri referrer = getReferrer();
            if (referrer != null) {
                callingPackage = referrer.getHost();
            }
        }

        if (callingPackage == null) {
            Log.w(TAG, "Unable to determine calling package");
            return false;
        }

        if (!ALLOWED_PACKAGES.contains(callingPackage)) {
            Log.w(TAG, "Caller not in whitelist: " + callingPackage);
            return false;
        }

        return true;
    }

    private boolean validateIntent(Intent intent) {
        String action = intent.getAction();
        String type = intent.getType();

        if (action == null || type == null) {
            Log.w(TAG, "Intent action or type is null");
            return false;
        }

        if (!Intent.ACTION_SEND.equals(action)) {
            Log.w(TAG, "Invalid action: " + action);
            return false;
        }

        if (type.startsWith("text/")) {
            return validateTextIntent(intent);
        } else if (type.startsWith("image/")) {
            return validateImageIntent(intent, type);
        }

        Log.w(TAG, "Unsupported type: " + type);
        return false;
    }

    private boolean validateTextIntent(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (TextUtils.isEmpty(sharedText)) {
            Log.w(TAG, "Shared text is empty");
            return false;
        }

        if (sharedText.length() > MAX_TEXT_LENGTH) {
            Log.w(TAG, "Shared text exceeds maximum length");
            return false;
        }

        return true;
    }

    private boolean validateImageIntent(Intent intent, String type) {
        if (!ALLOWED_IMAGE_TYPES.contains(type.toLowerCase())) {
            Log.w(TAG, "Image type not allowed: " + type);
            return false;
        }

        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri == null) {
            Log.w(TAG, "Image URI is null");
            return false;
        }

        String scheme = imageUri.getScheme();
        if (!"content".equals(scheme)) {
            Log.w(TAG, "Invalid URI scheme: " + scheme);
            return false;
        }

        try {
            getContentResolver().getType(imageUri);
        } catch (SecurityException e) {
            Log.w(TAG, "No permission to access URI: " + imageUri, e);
            return false;
        } catch (Exception e) {
            Log.w(TAG, "Error validating URI: " + imageUri, e);
            return false;
        }

        return true;
    }

    private void handleIntent(Intent intent) {
        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action) && type != null) {
            if (type.startsWith("text/")) {
                handleTextShare(intent);
            } else if (type.startsWith("image/")) {
                handleImageShare(intent);
            }
        }
    }

    private void handleTextShare(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        if (!TextUtils.isEmpty(sharedText)) {
            textView.setText(sanitizeText(sharedText));
            imageView.setVisibility(ImageView.GONE);
            textView.setVisibility(TextView.VISIBLE);
            Log.d(TAG, "Text shared successfully");
        }
    }

    private void handleImageShare(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri != null) {
            try {
                imageView.setImageURI(imageUri);
                imageView.setVisibility(ImageView.VISIBLE);
                textView.setVisibility(TextView.GONE);
                Log.d(TAG, "Image shared successfully");
            } catch (Exception e) {
                Log.e(TAG, "Error loading image", e);
                showError("Failed to load image");
            }
        }
    }

    private String sanitizeText(String text) {
        if (text == null) {
            return "";
        }
        text = text.trim();
        text = text.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "");
        return text;
    }

    private void showError(String message) {
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
        Log.e(TAG, message);
    }
}